/**
 * Shipping Calculator
 *
 * Supported destinations and their per-kg rates:
 *   - "domestic"         → weight * 2.5  (standard ground)
 *   - "international"    → weight * 7.5  (cross-border)
 *   - "express_domestic" → weight * 4.0  (expedited domestic)
 *   - "freight"          → weight * 1.5  (bulk / cheaper per-kg)
 *
 * Validation:
 *   - Weight must be > 0; otherwise throws with code INVALID_WEIGHT.
 *   - Unknown destination strings throw with code UNKNOWN_DESTINATION.
 *
 * Signature is intentionally unchanged per MJ's constraint.
 */

export class ShippingError extends Error {
  constructor(
    message: string,
    public readonly code: "INVALID_WEIGHT" | "UNKNOWN_DESTINATION"
  ) {
    super(message);
    this.name = "ShippingError";
  }
}

const RATES: Record<string, number> = {
  domestic: 2.5,
  international: 7.5,
  express_domestic: 4.0,
  freight: 1.5,
};

export function calculateShipping(weight: number, destination: string): number {
  if (weight <= 0) {
    throw new ShippingError(
      `Invalid weight: ${weight}. Weight must be greater than 0.`,
      "INVALID_WEIGHT"
    );
  }

  const rate = RATES[destination];

  if (rate === undefined) {
    throw new ShippingError(
      `Unknown destination: "${destination}". Valid destinations are: ${Object.keys(RATES).join(", ")}.`,
      "UNKNOWN_DESTINATION"
    );
  }

  return weight * rate;
}

